.shape-sort-board {
  min-height: 360px;
  padding: 16px;
}

.shape-tile {
  width: 72px;
  height: 72px;
  border-radius: 18px;
}

const shapeSortConfig = {
  tileSizePx: 72,
  dragPaddingPx: 6,
  snapTolerancePx: 16,
};

window.shapeSortConfig = shapeSortConfig;

function canGrabTile(pointer, tileRect) {
  const padding = shapeSortConfig.dragPaddingPx;
  return (
    pointer.x >= tileRect.left - padding &&
    pointer.x <= tileRect.right + padding &&
    pointer.y >= tileRect.top - padding &&
    pointer.y <= tileRect.bottom + padding
  );
}

window.canGrabShapeSortTile = canGrabTile;

:root {
  --portal-bg: #f6f1e7;
  --card-bg: #ffffff;
  --shadow: 0 10px 24px rgba(61, 48, 29, 0.12);
}

body {
  margin: 0;
  font-family: "Trebuchet MS", sans-serif;
  background: radial-gradient(circle at top, #fff8ea 0%, #f6f1e7 75%);
  color: #3d301d;
}

.portal-shell {
  max-width: 960px;
  margin: 0 auto;
  padding: 24px;
}

.game-card {
  background: var(--card-bg);
  border-radius: 18px;
  box-shadow: var(--shadow);
}

window.inputHelpers = {
  pointerSlopPx: 8,
  normalizePointer(point) {
    return {
      x: point.clientX,
      y: point.clientY,
    };
  },
};

