};

window.shapeSortConfig = shapeSortConfig;

// Detect touch device for larger touch targets
function isTouchDevice() {
  return 'ontouchstart' in window || navigator.maxTouchPoints > 0;
}

function getEffectiveDragPadding() {
  const basePadding = shapeSortConfig.dragPaddingPx;
  // Double the padding on touch devices for better touch targets
  return isTouchDevice() ? basePadding * 2 : basePadding;
}

function canGrabTile(pointer, tileRect) {
